# Geometry mapping
def _add_polyhedron_reader(prop, stl_path, priority):
    if not os.path.isfile(stl_path):
        raise FileNotFoundError(f'STL geometry file not found: {stl_path}')
    stl_file_type = getattr(CSPrimitives, 'STL_FILE', None)
    add_reader = getattr(prop, 'AddPolyhedronReader', None)
    if add_reader is None:
        raise RuntimeError('CSXCAD property object does not expose AddPolyhedronReader for STL-backed geometry.')
    attempts = [
        lambda: add_reader(stl_path, stl_file_type, priority),
        lambda: add_reader(stl_path, stl_file_type),
        lambda: add_reader(stl_path),
        lambda: add_reader(filename=stl_path, file_type=stl_file_type, priority=priority),
        lambda: add_reader(filename=stl_path, file_type=stl_file_type),
        lambda: add_reader(filename=stl_path),
    ]
    for call in attempts:
        try:
            return call()
        except TypeError:
            continue
    reader = add_reader()
    if reader is None:
        raise RuntimeError('AddPolyhedronReader returned no reader object for STL-backed geometry.')
    if hasattr(reader, 'SetFilename'):
        reader.SetFilename(stl_path)
    if stl_file_type is not None and hasattr(reader, 'SetFileType'):
        reader.SetFileType(stl_file_type)
    if hasattr(reader, 'SetPriority'):
        reader.SetPriority(priority)
    read_file = getattr(reader, 'ReadFile', None)
    if callable(read_file):
        read_ok = read_file()
        if read_ok is False:
            raise RuntimeError(f'Failed to read STL geometry: {stl_path}')
    return reader

