def _add_waveguide_port(fdtd, number, start, stop, direction, e_func, h_func, e_expr, h_expr, kc, excite):
    attempts = [
        # Canonical signature in current openEMS wheels: AddWaveGuidePort(..., E_func, H_func, kc, excite=0)
        lambda: fdtd.AddWaveGuidePort(number, start, stop, direction, e_func, h_func, kc, excite),
        lambda: fdtd.AddWaveGuidePort(number, start, stop, direction, e_func, h_func, kc),
        lambda: fdtd.AddWaveGuidePort(num=number, start=start, stop=stop, p_dir=direction, E_func=e_func, H_func=h_func, kc=kc, excite=excite),
        lambda: fdtd.AddWaveGuidePort(num=number, start=start, stop=stop, p_dir=direction, E_func=e_func, H_func=h_func, kc=kc),
        # Some openEMS builds expect iterable mode expressions rather than Python callables.
        lambda: fdtd.AddWaveGuidePort(number, start, stop, direction, e_expr, h_expr, kc, excite),
        lambda: fdtd.AddWaveGuidePort(number, start, stop, direction, e_expr, h_expr, kc),
    ]
    for call in attempts:
        try:
            return call()
        except TypeError:
            continue
    raise RuntimeError('Unable to call AddWaveGuidePort with supported signatures for this openEMS Python build.')

