# PORT OpenEMSPort: type=Waveguide num=1 R=8.81555581
# Waveguide TEM fields for port 1 (OpenEMSPort)
# Coax parameters: a=39.0, b=127.5, epsilon_r=65.0, Z0=8.815555806700585
# Coax center: (0.050024096929, 0.0, 50.0)
# Three-plane contract: face=ZMin, source_plane=6.0, reference_plane=8.0
port_1_coax_tem_a = 39.0
port_1_coax_tem_b = 127.5
port_1_coax_tem_z0 = 8.815555806700585
port_1_coax_tem_ln_ba = math.log(port_1_coax_tem_b / port_1_coax_tem_a)
port_1_coax_tem_cx = 0.050024096929
port_1_coax_tem_cy = 0.0
port_1_coax_tem_cz = 50.0
port_1_coax_tem_prop_sign = 1.0

def port_1_coax_tem_E(x, y, z):
    dx = x - port_1_coax_tem_cx
    dy = y - port_1_coax_tem_cy
    rho = math.sqrt(dx * dx + dy * dy)
    if rho <= port_1_coax_tem_a or rho >= port_1_coax_tem_b or rho == 0.0:
        return (0.0, 0.0, 0.0)
    e_mag = 1.0 / (rho * port_1_coax_tem_ln_ba)
    return (e_mag * dx / rho, e_mag * dy / rho, 0.0)

def port_1_coax_tem_H(x, y, z):
    dx = x - port_1_coax_tem_cx
    dy = y - port_1_coax_tem_cy
    rho = math.sqrt(dx * dx + dy * dy)
    if rho <= port_1_coax_tem_a or rho >= port_1_coax_tem_b or rho == 0.0:
        return (0.0, 0.0, 0.0)
    h_mag = 1.0 / (2.0 * math.pi * port_1_coax_tem_z0 * rho)
    s = port_1_coax_tem_prop_sign
    return (-s * h_mag * dy / rho, s * h_mag * dx / rho, 0.0)

