def _add_e_field_time_dump_plane(csx, dump_directory, start, stop):
    add_dump = getattr(csx, 'AddDump', None)
    if not callable(add_dump):
        raise RuntimeError('CSX object does not expose AddDump required for dump-plane export.')
    attempts = [
        lambda: add_dump('Et', dump_directory),
        lambda: add_dump('Et', subdir=dump_directory),
        lambda: add_dump('Et', filename=dump_directory),
        lambda: add_dump('Et'),
    ]
    dump_obj = None
    for call in attempts:
        try:
            dump_obj = call()
            break
        except TypeError:
            continue
    if dump_obj is None:
        raise RuntimeError('Unable to call AddDump with supported signatures for this openEMS Python build.')
    add_box = getattr(dump_obj, 'AddBox', None)
    if not callable(add_box):
        raise RuntimeError('Dump object does not expose AddBox for plane-region definition.')
    try:
        add_box(start, stop)
    except TypeError:
        add_box(start=start, stop=stop)
    return dump_obj
